+export async function drainNextQueueItem<T>(
+  items: T[],
+  run: (item: T) => Promise<void>,
+): Promise<boolean> {
+  const next = items[0];
+  if (!next) {
+    return false;
+  }
+  await run(next);
+  items.shift();
+  return true;
+}
